    Integer extractMin() {
        if (minNode == null) return null;
        Node minNode = this.minNode;
        if (minNode.child != null) {
            Node child = minNode.child;
            while (child != null) {
                child.sibling = this.minNode.sibling;
                this.minNode.sibling = child;
                child.parent = null;
                child = child.sibling;
            }
        }
        this.minNode = minNode.sibling;
        if (this.minNode == null) {
            nodeCount = 0;
            return minNode.value;
        }
        consolidate();
        nodeCount--;
        return minNode.value;
    }

