#include <stdlib.h>

typedef struct Node {
    int value;
    struct Node* child;
    struct Node* sibling;
    struct Node* parent;
    int degree;
    int marked;
} Node;

typedef struct FibonacciHeap {
    Node* minNode;
    int nodeCount;
} FibonacciHeap;

Node* createNode(int value) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->value = value;
    node->child = NULL;
    node->sibling = NULL;
    node->parent = NULL;
    node->degree = 0;
    node->marked = 0;
    return node;
}

FibonacciHeap* createFibonacciHeap() {
    FibonacciHeap* heap = (FibonacciHeap*)malloc(sizeof(FibonacciHeap));
    heap->minNode = NULL;
    heap->nodeCount = 0;
    return heap;
}

void insert(FibonacciHeap* heap, int value) {
    Node* newNode = createNode(value);
    if (!heap->minNode) {
        heap->minNode = newNode;
    } else {
        newNode->sibling = heap->minNode->sibling;
        heap->minNode->sibling = newNode;
        if (newNode->value < heap->minNode->value) {
            heap->minNode = newNode;
        }
    }
    heap->nodeCount++;
}

void link(FibonacciHeap* heap, Node* child, Node* parent) {
    child->sibling = parent->child;
    parent->child = child;
    child->parent = parent;
    parent->degree++;
    child->marked = 0;
}

void consolidate(FibonacciHeap* heap) {
    Node** aux = (Node**)calloc(heap->nodeCount + 1, sizeof(Node*));
    Node* current = heap->minNode;
    Node** nodes = (Node**)malloc(heap->nodeCount * sizeof(Node*));
    int nodeIndex = 0;
    while (current) {
        nodes[nodeIndex++] = current;
        current = current->sibling;
    }
    for (int i = 0; i < nodeIndex; i++) {
        Node* node = nodes[i];
        int degree = node->degree;
        while (aux[degree]) {
            Node* other = aux[degree];
            if (node->value > other->value) {
                Node* temp = node;
                node = other;
                other = temp;
            }
            link(heap, other, node);
            aux[degree] = NULL;
            degree++;
        }
        aux[degree] = node;
    }
    heap->minNode = NULL;
    for (int i = 0; i <= heap->nodeCount; i++) {
        if (aux[i] && (!heap->minNode || aux[i]->value < heap->minNode->value)) {
            heap->minNode = aux[i];
        }
    }
    free(aux);
    free(nodes);
}

int extractMin(FibonacciHeap* heap) {
    if (!heap->minNode) return -1;
    Node* minNode = heap->minNode;
    int minValue = minNode->value;
    if (minNode->child) {
        Node* child = minNode->child;
        while (child) {
            child->sibling = heap->minNode->sibling;
            heap->minNode->sibling = child;
            child->parent = NULL;
            child = child->sibling;
        }
    }
    heap->minNode = minNode->sibling;
    if (!heap->minNode) {
        heap->nodeCount = 0;
        free(minNode);
        return minValue;
    }
    consolidate(heap);
    heap->nodeCount--;
    free(minNode);
    return minValue;
}

int getMin(FibonacciHeap* heap) {
    return heap->minNode ? heap->minNode->value : -1;
}

void freeHeap(FibonacciHeap* heap) {
    Node* current = heap->minNode;
    while (current) {
        Node* next = current->sibling;
        free(current);
        current = next;
    }
    free(heap);
}

int main() {
    FibonacciHeap* heap = createFibonacciHeap();
    int values[] = {10, 20, 5, 30};
    for (int i = 0; i < 4; i++) {
        insert(heap, values[i]);
    }
    printf("Extracted min: %d\n", extractMin(heap));  // 5
    printf("New min: %d\n", getMin(heap));  // 10
    freeHeap(heap);
    return 0;
}
