class FibonacciHeap {
private:
    Node* minNode;
    int nodeCount;

    void link(Node* child, Node* parent) {
        child->sibling = parent->child;
        parent->child = child;
        child->parent = parent;
        parent->degree++;
        child->marked = false;
    }

    void consolidate() {
        std::vector<Node*> aux(nodeCount + 1, nullptr);
        Node* current = minNode;
        std::vector<Node*> nodes;
        while (current) {
            nodes.push_back(current);
            current = current->sibling;
        }
        for (Node* node : nodes) {
            int degree = node->degree;
            while (aux[degree]) {
                Node* other = aux[degree];
                if (node->value > other->value) {
                    std::swap(node, other);
                }
                link(other, node);
                aux[degree] = nullptr;
                degree++;
            }
            aux[degree] = node;
        }
        minNode = nullptr;
        for (Node* node : aux) {
            if (node && (!minNode || node->value < minNode->value)) {
                minNode = node;
            }
        }
    }

public:
    FibonacciHeap() : minNode(nullptr), nodeCount(0) {}

    void insert(int value) {
        Node* newNode = new Node(value);
        if (!minNode) {
            minNode = newNode;
        } else {
            newNode->sibling = minNode->sibling;
            minNode->sibling = newNode;
            if (newNode->value < minNode->value) {
                minNode = newNode;
            }
        }
        nodeCount++;
    }

    int extractMin() {
        if (!minNode) return -1;
        Node* minNode = this->minNode;
        int minValue = minNode->value;
        if (minNode->child) {
            Node* child = minNode->child;
            while (child) {
                child->sibling = this->minNode->sibling;
                this->minNode->sibling = child;
                child->parent = nullptr;
                child = child->sibling;
            }
        }
        this->minNode = minNode->sibling;
        if (!this->minNode) {
            nodeCount = 0;
            delete minNode;
            return minValue;
